def validate_token(token_string):
    """
    Validate an access token by checking:
    1. Token exists in the database (looked up by hash)
    2. Token is not expired
    3. Token is not revoked
    4. Associated client is still active

    Returns the token record if valid, None otherwise.
    """
    if not token_string or not isinstance(token_string, str):
        return None

    # Limit token length to prevent abuse
    if len(token_string) > 512:
        return None

    token_hashed = hash_token(token_string)
    db = get_db()

    token_record = db.execute(
        '''
        SELECT t.id, t.token_hash, t.client_id, t.user_id, t.scopes,
               t.expires_at, t.is_revoked, c.is_active as client_active,
               c.allowed_scopes as client_allowed_scopes
        FROM access_tokens t
        JOIN oauth_clients c ON t.client_id = c.client_id
        WHERE t.token_hash = ?
        ''',
        (token_hashed,)
    ).fetchone()

    if token_record is None:
        return None

    # Check if token is revoked
    if token_record['is_revoked']:
        return None

    # Check if client is active
    if not token_record['client_active']:
        return None

    # Check if token is expired
    expires_at = datetime.fromisoformat(token_record['expires_at']).replace(tzinfo=timezone.utc)
    now = datetime.now(timezone.utc)
    if now >= expires_at:
        return None

    return token_record


def check_scopes(token_record, required_scopes):
    """
    Validate that the token has ALL of the required scopes.
    Also validates that the token's scopes are a subset of the client's allowed scopes.

    Args:
        token_record: The validated token record from the database.
        required_scopes: A list/set of scope strings required for the endpoint.

    Returns:
        True if all required scopes are present and valid, False otherwise.
    """
    if not required_scopes:
        return True

    if token_record is None:
        return False

    # Parse token scopes
    token_scopes_str = token_record['scopes'] or ''
    token_scopes = set(s.strip() for s in token_scopes_str.split() if s.strip())

    # Parse client allowed scopes
    client_allowed_scopes_str = token_record['client_allowed_scopes'] or ''
    client_allowed_scopes = set(s.strip() for s in client_allowed_scopes_str.split() if s.strip())

    # Ensure token scopes are a subset of client's allowed scopes
    # This prevents scope escalation if a token was somehow issued with scopes
    # beyond what the client is allowed
