def create_client(client_name, allowed_scopes):
    """
    Create a new OAuth client. Returns client_id and client_secret.
    The secret is only shown once and stored as a hash.
    """
    client_id = secrets.token_urlsafe(16)
    client_secret = secrets.token_urlsafe(32)
    secret_hash = hash_secret(client_secret)

    db = sqlite3.connect(app.config['DATABASE'])
    db.execute(
        '''INSERT INTO oauth_clients (client_id, client_secret_hash, client_name, allowed_scopes)
           VALUES (?, ?, ?, ?)''',
        (client_id, secret_hash, client_name, ' '.join(allowed_scopes))
    )
    db.commit()
    db.close()

    return client_id, client_secret


def issue_token(client_id, user_id, scopes, expiry_seconds=None):
    """
    Issue a new access token for a client/user.
    Validates that requested scopes are within the client's allowed scopes.
    Returns the raw token string (only shown once).
    """
    if expiry_seconds is None:
        expiry_seconds = app.config['TOKEN_EXPIRY_SECONDS']

    db = sqlite3.connect(app.config['DATABASE'])
    db.row_factory = sqlite3.Row

    # Verify client exists and is active
    client = db.execute(
        'SELECT client_id, allowed_scopes, is_active FROM oauth_clients WHERE client_id = ?',
        (client_id,)
    ).fetchone()

    if client is None:
        db.close()
        raise ValueError(f"Client '{client_id}' not found.")

    if not client['is_active']:
        db.close()
        raise ValueError(f"Client '{client_id}' is not active.")

    # Validate requested scopes against client's allowed scopes
    client_allowed = set(s.strip() for s in (client['allowed_scopes'] or '').split() if s.strip())
    requested_scopes = set(scopes) if not isinstance(scopes, set) else scopes

    if client_allowed and not requested_scopes.issubset(client_allowed):
        invalid_scopes = requested_scopes - client_allowed
        db.close()
        raise ValueError(
            f"Requested scopes {invalid_scopes} are not allowed for client '{client_id}'. "
            f"Allowed scopes: {client_allowed}"
        )

    raw_token = secrets.token_urlsafe(48)
    token_hashed = hash_token(raw_token)
    expires_at = (datetime.now(timezone.utc) + timedelta(seconds=expiry_seconds)).isoformat()

    db.execute(
        '''INSERT INTO access_tokens (token_hash, client_id, user_id, scopes, expires_at)
           VALUES (?, ?, ?, ?, ?)''',
        (token_hashed, client_id, user_id, ' '.join(requested_scopes), expires_at)
    )
    db.commit()
    db.close()

    return raw_token


def cleanup_expired_tokens():
    """Remove expired and revoked tokens from the database."""
    db = sqlite3.connect(app.config['DATABASE'])
    now = datetime.now(timezone.utc).isoformat()
    cursor = db.execute(
        'DELETE FROM access_tokens WHERE expires_at < ? OR is_revoked = 1',
        (now,)
    )
    deleted = cursor.rowcount
    db.commit()
    db.close()
    return deleted


